import { useState, useEffect, useRef } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { ArrowLeft, Play, Volume2, VolumeX, Maximize, Minimize } from 'lucide-react';
import Navbar from '../components/layout/Navbar';
import { movieService } from '../services/api';

const WatchPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [movie, setMovie] = useState(null);
  const [muted, setMuted] = useState(false);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const videoRef = useRef(null);

  useEffect(() => {
    const fetchMovie = async () => {
      try {
        setLoading(true);
        const data = await movieService.getById(id);
        setMovie(data);
      } catch (err) {
        setError('Movie not found');
      } finally {
        setLoading(false);
      }
    };
    fetchMovie();
  }, [id]);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      videoRef.current?.parentElement?.requestFullscreen?.();
    } else {
      document.exitFullscreen?.();
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-black">
        <div className="flex items-center justify-center h-screen">
          <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-netflix-red"></div>
        </div>
      </div>
    );
  }

  if (error || !movie) {
    return (
      <div className="min-h-screen bg-netflix-bg">
        <Navbar />
        <div className="flex flex-col items-center justify-center h-screen">
          <h1 className="text-2xl text-white mb-4">{error || 'Movie not found'}</h1>
          <Link to="/" className="btn-primary">Go Home</Link>
        </div>
      </div>
    );
  }

  const isExternalPlayer = movie?.videoUrl?.includes('moviebox.') || 
                       movie?.videoUrl?.includes('netfilm.') || 
                       movie?.videoUrl?.includes('vki') || 
                       movie?.videoUrl?.includes('vidplay');

  const handleExternalWatch = () => {
    window.open(movie.videoUrl, '_blank', 'noopener,noreferrer');
  };

  return (
    <div className="min-h-screen bg-black">
      <div className="fixed top-0 left-0 right-0 z-50 p-4">
        <button 
          onClick={() => navigate(-1)} 
          className="flex items-center gap-2 text-white/80 hover:text-white transition-colors bg-black/50 px-3 py-2 rounded"
        >
          <ArrowLeft size={20} />
          Back
        </button>
      </div>

      <div className="relative h-screen bg-black flex items-center justify-center">
        {isExternalPlayer ? (
          <div className="flex flex-col items-center justify-center">
            <Play size={64} className="text-netflix-text-secondary mb-4" />
            <p className="text-netflix-text-secondary text-lg mb-4">Opening in new tab...</p>
            <button onClick={handleExternalWatch} className="btn-primary py-3 px-8">
              Click to Watch
            </button>
          </div>
        ) : movie.videoUrl ? (
          <video
            ref={videoRef}
            src={movie.videoUrl}
            controls
            className="w-full h-full object-contain"
            autoPlay
          />
        ) : (
          <div className="flex flex-col items-center justify-center">
            <Play size={64} className="text-netflix-text-secondary mb-4" />
            <p className="text-netflix-text-secondary text-lg">Video not available</p>
            <Link to={`/movie/${id}`} className="btn-primary mt-4">
              View Details
            </Link>
          </div>
        )}
      </div>
    </div>
  );
};

export default WatchPage;
